import{_ as s,c as e,a as n,o as p}from"./app-CEcM0piI.js";const h={};function r(i,a){return p(),e("div",null,a[0]||(a[0]=[n(`<h2 id="概念" tabindex="-1"><a class="header-anchor" href="#概念"><span>概念</span></a></h2><p>文件就是存放在磁盘上的一些数据的集合</p><h2 id="分类" tabindex="-1"><a class="header-anchor" href="#分类"><span>分类</span></a></h2><h4 id="磁盘文件-我们通常认识的文件" tabindex="-1"><a class="header-anchor" href="#磁盘文件-我们通常认识的文件"><span>磁盘文件:(我们通常认识的文件)</span></a></h4><p>指一组相关数据的有序集合,通常存储在外部介质(如磁盘)上，使用时才调入内存。</p><p>一个文件通常是磁盘上一段命名的存储区计算机的存储在物理上是二进制的，所以物理上所有的磁盘文件本质上都是一样的:以字节为单位进行顺序存储</p><h5 id="从用户或者操作系统使用的角度-逻辑上-把文件分为" tabindex="-1"><a class="header-anchor" href="#从用户或者操作系统使用的角度-逻辑上-把文件分为"><span>从用户或者操作系统使用的角度(逻辑上)把文件分为:</span></a></h5><h6 id="文本文件-基于字符编码的文件" tabindex="-1"><a class="header-anchor" href="#文本文件-基于字符编码的文件"><span>文本文件:基于字符编码的文件</span></a></h6><p>常见编码有 ASCII、UNICODE 等一般可以使用文本编辑器直接打开 例如:数5678 的以ASCII 存储形式为:ASCI码: 00110101 00110110 00110111 00111000</p><h6 id="二进制文件-基于值编码的文件" tabindex="-1"><a class="header-anchor" href="#二进制文件-基于值编码的文件"><span>二进制文件:基于值编码的文件</span></a></h6><p>基于值编码,根据具体应用,指定某个值是什么意思一般需要自己判断或使用特定软件分析数据格式 例如:数 5678 的存储形式为:二进制码:00010110 00101110</p><p>音频文件(mp3):二进制文件 图片文件(bmp)文件，一个像素点由两个字节来描述<span class="katex-error" title="ParseError: KaTeX parse error: Expected &#39;EOF&#39;, got &#39;#&#39; at position 6: *****#̲#####&amp;&amp;&amp;&amp;&amp;，565" style="color:#cc0000;">*****######&amp;&amp;&amp;&amp;&amp;，565</span><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo>∗</mo><mtext>代表红色的值</mtext><mi>R</mi></mrow><annotation encoding="application/x-tex">* 代表红色的值 R</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6833em;"></span><span class="mord">∗</span><span class="mord cjk_fallback">代表红色的值</span><span class="mord mathnormal" style="margin-right:0.00773em;">R</span></span></span></span><span class="katex-error" title="ParseError: KaTeX parse error: Expected &#39;EOF&#39;, got &#39;#&#39; at position 1: #̲代表绿色的值 G" style="color:#cc0000;">#代表绿色的值 G</span> &amp;代表蓝色的值 B</p><h5 id="文本文件、二进制文件对比" tabindex="-1"><a class="header-anchor" href="#文本文件、二进制文件对比"><span>文本文件、二进制文件对比:</span></a></h5><h6 id="译码" tabindex="-1"><a class="header-anchor" href="#译码"><span>译码:</span></a></h6><p>文本文件编码基于字符定长，译码容易些; 二进制文件编码是变长的，译码难一些(不同的二进制文件格式，有不同的译码方式，一般需要特定软件进行译码)。</p><h6 id="空间利用率" tabindex="-1"><a class="header-anchor" href="#空间利用率"><span>空间利用率:</span></a></h6><p>二进制文件用一个比特来代表一个意思(位操作) 而文本文件任何一个意思至少是一个字符。空间利用率高</p><h6 id="可读性" tabindex="-1"><a class="header-anchor" href="#可读性"><span>可读性:</span></a></h6><p>文本文件用通用的记事本工具就几乎可以浏览所有文本文件 二讲制文件需要一个具体的文件解码器，比如读 BM 文件，必须用读图软件 视频文件需要视频播放器</p><h5 id="总结" tabindex="-1"><a class="header-anchor" href="#总结"><span>总结:</span></a></h5><p>1、文件在硬盘上存储的时候，物理上都是用二进制来存储的 2、咱们的标准 io 库函数，对文件操作的时候，不管文件的编码格式(字符编码、或二进制)，而是按字节对文件进行读写，所以咱们管文件又叫流式文件，即把文件看成一个字节流。</p><h4 id="设备文件" tabindex="-1"><a class="header-anchor" href="#设备文件"><span>设备文件:</span></a></h4><p>输出等同于在操作系统中把每一个与主机相连的输入、输出设备看作是一个文件，把它们的输入、:对磁盘文件的读和写。</p><p>标准io库函数对磁盘文件的读取特点 ![[Pasted image 20230924170024.png]]</p><p>VS 中对普通文件的读写是全缓冲的。</p><h4 id="全缓冲" tabindex="-1"><a class="header-anchor" href="#全缓冲"><span>全缓冲</span></a></h4><p>标准 io 库函数 ，往普通文件读写数据的，是全缓冲的</p><h4 id="刷新缓冲区的情况" tabindex="-1"><a class="header-anchor" href="#刷新缓冲区的情况"><span>刷新缓冲区的情况</span></a></h4><p>1.缓冲区满了，刷新缓冲区 2.调用函数刷新缓冲区 fush(文件指针) 3.程序结束 会刷新缓冲区</p><h1 id="文件指针" tabindex="-1"><a class="header-anchor" href="#文件指针"><span>文件指针</span></a></h1><p>文件指针在程序中用来标识(代表)一个文件的，在打开文件的时候得到文件指针,文件指针就用来代表打开的文件。</p><p>对文件进行读、写、关闭等操作的时候，对文件指针进行操作即可，即将文件指针，传给读、写、关闭等函数，那些函数就知道要对哪个文件进行操作。</p><h2 id="定义文件指针" tabindex="-1"><a class="header-anchor" href="#定义文件指针"><span>定义文件指针</span></a></h2><p>FILE* 指针变量标符; FILE 为大写，需要包含&lt;stdio.h&gt;</p><p>FILE 是系统使用 typedef定义出来的有关文件信息的一种结构体类型，结构中含有文件名、文件状态和文件当前位置等信息</p><p>般情况下，我们操作文件前必须定义一个文件指针标识 我们将要操作的文件实际编程中使用库函数操作文件，无需关心FILE 结构体的细节 ，只需要将文件指针传给 io 库函数库函数再通过 FILE 结构体里的信息对文件进行操作</p><h2 id="file-在-stdio-h-文件中的文件类型声明" tabindex="-1"><a class="header-anchor" href="#file-在-stdio-h-文件中的文件类型声明"><span>FILE 在 stdio.h 文件中的文件类型声明:</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>typedef struct{</span></span>
<span class="line"><span>	short level;	//缓冲区“满”或“空”的程度</span></span>
<span class="line"><span>	unsigned flags;	//文件状态标志</span></span>
<span class="line"><span>	char fd;	//文件描述符</span></span>
<span class="line"><span>	unsigned charhold;	//如无缓冲区不读取字符</span></span>
<span class="line"><span>	short bsize;	//缓冲区的大小</span></span>
<span class="line"><span>	unsigned char *buffer;	//数据缓冲区的位置</span></span>
<span class="line"><span>	unsigned ar*curp;	//指针，当前的指向</span></span>
<span class="line"><span>	unsigned istemp;	//临时文件，指示器</span></span>
<span class="line"><span>	shorttoken;	//用于有效性检查</span></span>
<span class="line"><span>}FILE;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在缓冲文件系统中,每个被使用的文件都要在内存中开辟一块FILE 类型的区域存放与操作文件相关的信息</p><h1 id="文件打开和关闭" tabindex="-1"><a class="header-anchor" href="#文件打开和关闭"><span>文件打开和关闭</span></a></h1><h2 id="对文件操作的步骤" tabindex="-1"><a class="header-anchor" href="#对文件操作的步骤"><span>对文件操作的步骤:</span></a></h2><p>1、对文件进行读写等操作之前要打开文件得到文件指针 2、可以通过文件指针对文件进行读写等操作 3、读写等操作完毕后，要关闭文件，关闭文件后，就不能再通过此文件指针操作文件了</p><h2 id="补充" tabindex="-1"><a class="header-anchor" href="#补充"><span>补充:</span></a></h2><p>c 语言中有三个特殊的文件指针无需定义，在程序中可以直接使用</p><h4 id="stdin-标准输入-默认为当前终端-键盘" tabindex="-1"><a class="header-anchor" href="#stdin-标准输入-默认为当前终端-键盘"><span>stdin: 标准输入 默认为当前终端(键盘)</span></a></h4><p>我们使用的scanf、getchar函数默认从此终端获得数据</p><h4 id="stdout-标准输出默认为当前终端-屏幕" tabindex="-1"><a class="header-anchor" href="#stdout-标准输出默认为当前终端-屏幕"><span>stdout: 标准输出默认为当前终端(屏幕)</span></a></h4><p>我们使用的 printf、puts 函数默认输出信息到此终端</p><h4 id="stderr-标准错误输出设备文件-默认为当前终端-屏幕" tabindex="-1"><a class="header-anchor" href="#stderr-标准错误输出设备文件-默认为当前终端-屏幕"><span>stderr:标准错误输出设备文件 默认为当前终端(屏幕)</span></a></h4><p>当我们程序出错使用:perror 函数时信息打印在此终端</p><h1 id="fopen" tabindex="-1"><a class="header-anchor" href="#fopen"><span>fopen</span></a></h1><h2 id="函数的声明" tabindex="-1"><a class="header-anchor" href="#函数的声明"><span>函数的声明:</span></a></h2><p>FILE * fopen(const char * path, const char * mode);</p><p>打开一个已经存在的文件，并返回这个文件的文件指针(文件的标识)或者创建一个文件，并打开此文件，然后返回文件的标示。</p><p>返回值: 成功:打开的文件对应的文件指针 失败:返回 NULL 调用 fopen,函数的时候，一定要判断一下，打开是否成功</p><h2 id="函数的参数" tabindex="-1"><a class="header-anchor" href="#函数的参数"><span>函数的参数:</span></a></h2><h4 id="参数-1-打开的文件的路径" tabindex="-1"><a class="header-anchor" href="#参数-1-打开的文件的路径"><span>参数 1:打开的文件的路径</span></a></h4><p>1、绝对路径,从根目录开始的路径名称 &quot;D:\\\\demo\\\\test\\\\aaa.txt&quot;</p><p>2、相对路径 test\\\\aaa.txt</p><h4 id="参数-2-文件打开的方式" tabindex="-1"><a class="header-anchor" href="#参数-2-文件打开的方式"><span>参数 2:文件打开的方式</span></a></h4><p>即以什么样的方式(只读、只写、可读可写等等)打开文件</p><h2 id="第二个参数的几种形式-打开文件的方式" tabindex="-1"><a class="header-anchor" href="#第二个参数的几种形式-打开文件的方式"><span>第二个参数的几种形式(打开文件的方式)</span></a></h2><p>读写权限:r w a +</p><p>r:以只读方式打开文件 文件不存在返回 NULL; 文件存在，且打开文件成功，返回文件指针，进行后续的读操作</p><p>例</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>FILE* fp;</span></span>
<span class="line"><span>fp=fopen(&quot;test.txt&quot;,&quot;r&quot;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>w:以只写方式打开文件 1、文件不存在，以指定文件名创建此文件，并且打开文件; 2、若文件存在，清空文件内容，打开文件，然后进行写操作; 3、如果文件打不开(比如文件只读)，返回 NULL</p><p>a:以追加方式打开文件 1、文件不存在，以指定文件名创建此文件(同 w) 2、若文件存在，从文件的结尾处进行写操作</p><p>如果不加 a 的话，打开文件的时候读写位置在文件的开始，对文件进行读写的时候都是从文件开始进行读写的。 如果加 a，打开已经存在的文件，读写位置在文件的末尾。</p><h2 id="打开方式" tabindex="-1"><a class="header-anchor" href="#打开方式"><span>打开方式</span></a></h2><p><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>带</mtext><mi>b</mi><mtext>的都是当作二进制文件打开</mtext></mrow><annotation encoding="application/x-tex">带b的都是当作二进制文件打开</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6944em;"></span><span class="mord cjk_fallback">带</span><span class="mord mathnormal">b</span><span class="mord cjk_fallback">的都是当作二进制文件打开</span></span></span></span></p><p>r以只读方式打开一个文本文件不创建文件 rb把文件当作二进制文件打开 r+以可读、可写的方式打开文件(不创建新文件) rb+</p><p>w以写方式打开文件(使文件长度截断为 0 字节，创建一个文件) wb w+以可读、可写的方式打开文件(使文件长度为 0 字节，创建一个文件) wb+</p><p>a以追加方式打开文件，即在末尾添加内容，当文件不存在时，创建文件用于写 ab a+以添加方式打开文件，打开文件并在末尾更改文件(如果文件不存在，则创建文件) ab+</p><h1 id="fclose" tabindex="-1"><a class="header-anchor" href="#fclose"><span>fclose</span></a></h1><h2 id="函数的声明-1" tabindex="-1"><a class="header-anchor" href="#函数的声明-1"><span>函数的声明:</span></a></h2><p>int fclose(FILE * fp);</p><h2 id="函数的说明" tabindex="-1"><a class="header-anchor" href="#函数的说明"><span>函数的说明:</span></a></h2><p>关闭 fp 所代表的文件 一个文件只能关闭一次，不能多次关闭。关闭文件之后就不能再文件指针对文件进行读写等操作了</p><p>返回值: 成功返回0 失败返回非0 可以通过返回值，来判断关闭文件是否成功。</p><h1 id="读写字符" tabindex="-1"><a class="header-anchor" href="#读写字符"><span>读写字符</span></a></h1><h1 id="fgetc" tabindex="-1"><a class="header-anchor" href="#fgetc"><span>fgetc</span></a></h1><h2 id="函数声明" tabindex="-1"><a class="header-anchor" href="#函数声明"><span>函数声明:</span></a></h2><p>int fgetc(FILE * stream);</p><h2 id="函数说明" tabindex="-1"><a class="header-anchor" href="#函数说明"><span>函数说明:</span></a></h2><p>fgetc 从 stream 所标识的文件中读取一个字节，将字节值返回</p><h2 id="返回值" tabindex="-1"><a class="header-anchor" href="#返回值"><span>返回值:</span></a></h2><p>以t的方式:读到文件结尾返回 EOF 以 b的方式:读到文件结尾，使用 feof(文件指针)判断结尾</p><p>feof是 C 语言标准库函数，其原型在 stdio.h 中，其功能是检测流上的文件结束符，如果文件结束则返回非0值，否则返回 0(即，文件结束:返回非0值；文件未结束:返回0值)。</p><h1 id="fputc" tabindex="-1"><a class="header-anchor" href="#fputc"><span>fputc</span></a></h1><h2 id="函数的声明-2" tabindex="-1"><a class="header-anchor" href="#函数的声明-2"><span>函数的声明:</span></a></h2><p>int fputc(int c, FILE * stieam);</p><h2 id="函数的说明-1" tabindex="-1"><a class="header-anchor" href="#函数的说明-1"><span>函数的说明:</span></a></h2><p>fputc将 c的值写到 stream 所代表的文件中。也可以是stout（屏幕上）</p><p>返回值: 如果输出成功，则返回输出的字节值 如果输出失败，则返回一个 EOF。</p><p>EOF 是在 stdio.h 文件中定义的符号常量，值为-1</p><p>注意:打开文件的时候，默认读写位置在文件的开始，如果以 a 的方式打开读写位置在文件的末尾向文件中读取字节或写入字节的时候，读写位置会往文件的末尾方向偏移，读写多少个字节，读写位置就往文件的末尾方向偏移多少个字节</p><h1 id="fgets" tabindex="-1"><a class="header-anchor" href="#fgets"><span>fgets</span></a></h1><p>char * fgets(char * s,int size, FILE * stream);</p><p>从 stream 所代表的文件中读取字符，在读取的时候碰到换行符或者是碰到文件的末尾停止读取,或者是读取了 size-1个字节停止读取，在读取的内容后面会加一个\\0,作为字符串的结尾</p><p>返回值: 成功返回目的数组的首地址，即 s 失败返回 NULL</p><h1 id="fputs" tabindex="-1"><a class="header-anchor" href="#fputs"><span>fputs</span></a></h1><p>int fputs(const char * s, FILE * stream); 函数功能: 将s 指向的字符串，写到 stream 所代表的文件中 返回值: 成功返回写入的字节数 失败返回 -1</p><h1 id="读写文件" tabindex="-1"><a class="header-anchor" href="#读写文件"><span>读写文件</span></a></h1><h1 id="fread" tabindex="-1"><a class="header-anchor" href="#fread"><span>fread</span></a></h1><h2 id="函数的声明-3" tabindex="-1"><a class="header-anchor" href="#函数的声明-3"><span>函数的声明:</span></a></h2><p>size t fread(void * ptr, size t size, size t nmemb, FILE * stream);</p><h2 id="函数的说明-2" tabindex="-1"><a class="header-anchor" href="#函数的说明-2"><span>函数的说明:</span></a></h2><p>fread 函数从 stream 所标识的文件中读取数据，每块是 size 个字节，共memb 块，存放到 p 指向的内存里</p><h2 id="返回值-1" tabindex="-1"><a class="header-anchor" href="#返回值-1"><span>返回值:</span></a></h2><p>实际读到的块数</p><h1 id="fwrite" tabindex="-1"><a class="header-anchor" href="#fwrite"><span>fwrite</span></a></h1><h2 id="函数的声明-4" tabindex="-1"><a class="header-anchor" href="#函数的声明-4"><span>函数的声明:</span></a></h2><p>size t fwrite(void * ptr, size_t size, size t nmemb, FILE * stream);</p><h2 id="函数的说明-3" tabindex="-1"><a class="header-anchor" href="#函数的说明-3"><span>函数的说明:</span></a></h2><p>fwrite 函数将pt 指向的内存里的数据，向 stream 所标识的文件中写入数据，每块是 size 个字节，共nmemb 块。</p><p>返回值: 实际写入的块数</p><h1 id="随机读写" tabindex="-1"><a class="header-anchor" href="#随机读写"><span>随机读写</span></a></h1><h1 id="rewind-复位读写位置" tabindex="-1"><a class="header-anchor" href="#rewind-复位读写位置"><span>rewind 复位读写位置</span></a></h1><h4 id="定义" tabindex="-1"><a class="header-anchor" href="#定义"><span>定义</span></a></h4><p>void rewind(文件指针)</p><h4 id="函数功能" tabindex="-1"><a class="header-anchor" href="#函数功能"><span>函数功能</span></a></h4><p>把文件内部的位置指针移到文件首调用形式</p><h4 id="调用方式" tabindex="-1"><a class="header-anchor" href="#调用方式"><span>调用方式</span></a></h4><p>rewind(文件指针)</p><h1 id="ftell-测文件读写位置距文件开始有多少个字节" tabindex="-1"><a class="header-anchor" href="#ftell-测文件读写位置距文件开始有多少个字节"><span>ftell 测文件读写位置距文件开始有多少个字节</span></a></h1><h4 id="定义函数" tabindex="-1"><a class="header-anchor" href="#定义函数"><span>定义函数:</span></a></h4><p>long ftel1(文件指针);</p><h4 id="函数功能-1" tabindex="-1"><a class="header-anchor" href="#函数功能-1"><span>函数功能:</span></a></h4><p>取得文件流目前的读写位置</p><h4 id="返回值-2" tabindex="-1"><a class="header-anchor" href="#返回值-2"><span>返回值:</span></a></h4><p>返回当前读写位置(距离文件起始的字节数)，出错时返回-1.</p><h1 id="fseek-定位位置指针-读写位置-fseek-函数-一般用于二进制文件即打开文件的方式需要带-b" tabindex="-1"><a class="header-anchor" href="#fseek-定位位置指针-读写位置-fseek-函数-一般用于二进制文件即打开文件的方式需要带-b"><span>fseek 定位位置指针(读写位置)fseek 函数 (一般用于二进制文件即打开文件的方式需要带 b)</span></a></h1><h2 id="函数声明-1" tabindex="-1"><a class="header-anchor" href="#函数声明-1"><span>函数声明:</span></a></h2><p>int fseek(FILE * stream, long offset, int whence); //int fseek(文件类型指针，位移量，起始点);</p><h2 id="函数功能-2" tabindex="-1"><a class="header-anchor" href="#函数功能-2"><span>函数功能:</span></a></h2><p>移动文件流的读写位置</p><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数"><span>参数:</span></a></h2><p>whence 起始位置 文件开头 SEEK SET 0 文件当前位置 SEEK CUR 1 文件末尾 SEEK END 2</p><h2 id="位移量" tabindex="-1"><a class="header-anchor" href="#位移量"><span>位移量:</span></a></h2><p>以起始点为基点，向前、后移动的字节数，正数往文件末尾方向偏移，负数往文件开头方向偏移。</p>`,141)]))}const d=s(h,[["render",r]]),c=JSON.parse('{"path":"/cpp/c/7/","title":"7 文件操作","lang":"zh-CN","frontmatter":{"title":"7 文件操作","createTime":"2025/06/22 10:05:50","permalink":"/cpp/c/7/"},"readingTime":{"minutes":10.27,"words":3080},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C/7 文件操作.md","headers":[]}');export{d as comp,c as data};
